'use strict'

$(() => {

    // Burger --->
    $('.burger__btn').on('click', function() {
        $(this).parent().toggleClass('opened');
    })



    // СТРАНИЦА: index --->
    // Слайдер партнеров
    $('#slider-companies').slick({
        prevArrow: $('.information__footer .btn-prev'),
        nextArrow: $('.information__footer .btn-next'),
        slidesToShow: 6,
        responsive: [
            {
                breakpoint: 900,
                settings: {
                    slidesToShow: 5,
                }
            },
            {
                breakpoint: 700,
                settings: {
                    slidesToShow: 4,
                }
            },
            {
                breakpoint: 600,
                settings: {
                    slidesToShow: 3,
                }
            },
            {
                breakpoint: 500,
                settings: {
                    slidesToShow: 1,
                }
            },
        ]
    });

    // Слайдер новостей
    $('#slider-news').slick({
        prevArrow: $('.news .btn-prev'),
        nextArrow: $('.news .btn-next'),
        infinite: true,
        slidesToShow: 2,
        slidesToScroll: 1,
        responsive: [
            {
                breakpoint: 1000,
                settings: {
                    slidesToShow:1,
                }
            }
        ]
    });

    // Класс для хедера при скролле
    function addClassToTheHeaderOnScroll() {
        if ($('body').scrollTop() > 140) {
            $('.header').addClass('header--scrolling');
            return
        }
        $('.header').removeClass('header--scrolling'); 
    }
    addClassToTheHeaderOnScroll();
    $('body').on('scroll', addClassToTheHeaderOnScroll);

    // Всплывающий поп-ап при наведении на отдельные регионы России
    const locations = {
        'M404.982': 'Иркуртск', 
        'M313.003': 'Томск', 
        'M222.545': 'Ханты-Мансийск',
        'M245.178': 'Тюмень',
        'M268.078': 'Ямало-Ненецкий автономный округ',
        'M253.74': 'Архангельск',
        'M196.325': 'Перьм',
        'M149.198': 'Самара',
        'M149.004': 'Оренбург',
        'M128.622': 'Саратов',
    }
    $('.geography__img-container path[fill="#6DF2E5"]').on('mouseover', function() {
        const id = $(this).attr('d').slice(0, 8).trim();
        mousePopUp(true, locations[id]);
    })
    $('.geography__img-container path[fill="#6DF2E5"]').on('mouseout', function() {
        mousePopUp(false);
    })

    function mousePopUp(turnOn, text) {
        if (turnOn === false) {
            $('body').off("mousemove");
            $('.mouse-pop-up').css({ top: 0, left:-100 });
            return
        }
        
        $('body').on('mousemove', (event) => {
            $('.mouse-pop-up').text(text);
            $('.mouse-pop-up').css({ top: event.pageY - 70, left: event.pageX - ($('.mouse-pop-up').width() / 2) - 17 });
        })
    }



    // СТРАНИЦА: activities --->
    // Слайдер деятельностей
    $('.activity__slider-list').slick({
        infinite: true,
        slidesToShow: 1,
        slidesToScroll: 1,
        arrows: false,
        dots: true,
        adaptiveHeight: true,
    });
    
    // Плавный скролл
    $('.activities__link[href^="#"]').on('click', function (e) {
        e.preventDefault();
        const id = $(this).attr('href');
        console.log(document.querySelector(id));
        document.querySelector(id).scrollIntoView({
            behavior: 'smooth',
            block: 'start'
        });
    });



    // СТРАНИЦА: about-company --->
    // Слайдер команд
    $('.team__slider').slick({
        infinite: true,
        slidesToShow: 1,
        slidesToScroll: 1,
        arrows: true,
        dots: false,
        centerMode: true,
        adaptiveHeight: false,
        prevArrow: $('.team__slider-container .btn-prev'),
        nextArrow: $('.team__slider-container .btn-next'),
        responsive: [
            {
                breakpoint: 1100,
                settings: {
                    centerMode: false,
                    
                }
            },
            {
                breakpoint: 800,
                settings: {
                    centerMode: false,
                    adaptiveHeight: true,
                    
                }
            }
        ]
    });
    $('.projects__slider').slick({
        infinite: false,
        slidesToShow: 1,
        slidesToScroll: 1,
        arrows: true,
        dots: true,
        dotsClass: 'slick-dots slider__dots',
        prevArrow: $('.projects .btns-cont .btn-prev'),
        nextArrow: $('.projects .btns-cont .btn-next'),
        responsive: [
            {
                breakpoint: 800,
                settings: {
                    adaptiveHeight: true,
                }
            }
        ]
    });


    // СТРАНИЦА: career --->
    // Слайдер школы
    $('.school__slider').slick({
        infinite: false,
        slidesToShow: 1,
        arrows: false,
        dots: false,
        autoplay: true,
        autoplaySpeed: 2500,
        fade: true,
    });

    // Слайдер работников
    $('.workers__slider').slick({
        infinite: false,
        slidesToShow: 1,
        slidesToScroll: 1,
        speed: 300,
        arrows: true,
        prevArrow: $('.workers__btns .btn-prev'),
        nextArrow: $('.workers__btns .btn-next'),
        adaptiveHeight: true,
    });

    // Аккордеон
    const accordionButtons = $('.vacancies__accordion-btn');
    const accordionTexts = $('.vacancies__accordion-text');
  
    function RunAccordion(buttons, texts) {
        for (let i = 0; i < $(buttons).length; i++) { // Пробегаемся по кнопка
            const button = $(buttons)[i]; // Кладем текущую кнопку в переменную
            const text = $(texts)[i]; // Кладем в переменную текст с таким же index как и у кнопки

            $(button).on('click', () => { // Навещиваем обработчик на кнопку
                
                $(button).toggleClass('hide'); // Переключаем класс hide у кнопки
                $(button).parent().toggleClass('dark');
                const textClosed = $(button).hasClass('hide'); // textClosed содержит true если копка имеет класс hide
                
                $(text).css('height', textClosed ? '0px' : `${text.scrollHeight + 30}px`) // Если не имеет класс hide, добавить внутренние отступы
            }) 
        }
    }
    RunAccordion(accordionButtons, accordionTexts);
})
//# sourceMappingURL=data:application/json;charset=utf8;base64,
